<?php
declare(strict_types=1);require_once dirname(__DIR__).'/includes/cms.php';require_once dirname(__DIR__,3).'/includes/comunicaciones.php';require_once dirname(__DIR__,3).'/includes/mailer.php';require_once dirname(__DIR__,3).'/includes/errores_sistema.php';exigirPermiso('communications.reply');$id=cmsId($_POST['id']??0);$mensaje=textoComunicacionAtenea((string)($_POST['mensaje']??''));if(($_SERVER['REQUEST_METHOD']??'')!=='POST'||!validarTokenCsrf((string)($_POST['csrf_token']??''))||$mensaje===''){cmsFlash('error','Solicitud inválida.');header('Location:index.php');exit;}$pdo=obtenerConexion();$q=$pdo->prepare('SELECT h.*,COALESCE(u.correo,h.correo_contacto) destinatario,CONCAT_WS(\' \',u.nombre,u.apellido) nombre_usuario FROM comunicacion_hilos h LEFT JOIN usuarios u ON u.id=h.usuario_id WHERE h.id=:id');$q->execute(['id'=>$id]);$h=$q->fetch();if(!$h||!filter_var($h['destinatario'],FILTER_VALIDATE_EMAIL)){cmsFlash('error','El hilo no tiene un correo válido.');header('Location:hilo.php?id='.$id);exit;}$q=$pdo->prepare("INSERT INTO comunicacion_mensajes(hilo_id,direccion,autor_usuario_id,autor_nombre,contenido,resultado_envio) VALUES(:h,'salida',:u,'Administracion Atenea',:m,'pendiente')");$q->execute(['h'=>$id,'u'=>$_SESSION['usuario_id'],'m'=>$mensaje]);$mid=(int)$pdo->lastInsertId();$pdo->prepare("UPDATE comunicacion_hilos SET estado='respondido',ultimo_mensaje_at=NOW() WHERE id=:id")->execute(['id'=>$id]);try{$html='<div style="font-family:Arial;color:#26342c"><h2 style="color:#4b7f52">Respuesta de Atenea</h2><p>'.nl2br(atenea_e($mensaje)).'</p></div>';enviarCorreoAtenea($h['destinatario'],$h['nombre_usuario']?:$h['nombre_contacto'],'Re: '.$h['asunto'],$html,$mensaje,['tipo'=>'respuesta_administrativa','usuario_id'=>$h['usuario_id'],'pedido_id'=>$h['pedido_id'],'hilo_id'=>$id,'idempotency_key'=>'hilo:'.$id.':mensaje:'.$mid]);$q=$pdo->prepare('SELECT id,estado FROM correo_envios WHERE idempotency_key=:k');$q->execute(['k'=>'hilo:'.$id.':mensaje:'.$mid]);$c=$q->fetch();$pdo->prepare('UPDATE comunicacion_mensajes SET correo_envio_id=:c,resultado_envio=:r WHERE id=:id')->execute(['c'=>$c['id']??null,'r'=>($c['estado']??'')==='enviado'?'enviado':'fallido','id'=>$mid]);if($h['usuario_id'])crearNotificacionAtenea(['usuario_id'=>$h['usuario_id'],'created_by'=>$_SESSION['usuario_id'],'tipo'=>'respuesta','categoria'=>'comunicaciones','nivel'=>'informacion','titulo'=>'Atenea respondió tu consulta','descripcion'=>mb_substr($mensaje,0,300),'url'=>atenea_url('src/estudiantes/index.php'),'hilo_id'=>$id,'idempotency_key'=>'hilo:respuesta:'.$mid],$pdo);cmsFlash('exito','Respuesta guardada y enviada.');}catch(Throwable $e){$pdo->prepare("UPDATE comunicacion_mensajes SET resultado_envio='fallido' WHERE id=:id")->execute(['id'=>$mid]);registrarErrorSistemaAtenea('correo','comunicaciones',sanitizarErrorCorreoAtenea($e),['hilo_id'=>$id,'usuario_id'=>$h['usuario_id'],'pedido_id'=>$h['pedido_id']]);cmsFlash('error','La respuesta quedó guardada, pero el correo falló y puede reintentarse.');}header('Location:hilo.php?id='.$id);
